                      </Button>
                    </Link>
                  </TableCell>
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={6} className="text-center py-8">
                  <p className="text-muted-foreground">
                    {status && status !== 'todos'
                      ? `No hay pedidos con estado "${statusLabels[status] || status}"`
                      : 'No hay pedidos registrados'}
                  </p>
                </TableCell>
              </TableRow>
            )}
